const marketing = {
  id: 'marketing',
  title: 'Web3 Marketing',
  emoji: '📢',
  color: '#EF4444',
  gradient: ['#B91C1C', '#EF4444'],
  description: 'Build communities, launch tokens, and grow Web3 projects with proven crypto-native strategies.',
  category: 'Marketing',
  modules: [
    {
      id: 'marketing_beg',
      level: 'beginner',
      title: 'Web3 Marketing Basics',
      emoji: '🌱',
      description: 'Understand how crypto projects market differently from traditional companies.',
      color: '#EF4444',
      lessons: [
        { id: 'mkt_beg_l1', title: 'Web3 Marketing vs Traditional Marketing', slides: [
          { type: 'intro', title: 'Community Over Advertising', body: 'Traditional marketing: pay to reach customers. Web3 marketing: build a community that becomes your distribution network, investor base, and product testers simultaneously. The model is fundamentally different — and far more powerful when executed correctly.' },
          { type: 'text', title: 'The Core Shift', body: 'In Web2: users are the product (data sold to advertisers). In Web3: users are stakeholders (they own tokens, they have governance rights). This changes the marketing relationship entirely. Web3 users are more skeptical, more research-oriented, and more demanding of genuine value — but also more loyal when you earn their trust.' },
          { type: 'text', title: 'Why Twitter is the Web3 Town Square', body: 'Every crypto project lives or dies on Crypto Twitter (CT). News breaks there first. Narratives form there. FUD spreads there. Alpha leaks there. Your project\'s Twitter presence is your first impression to every potential user, investor, and partner. A dead Twitter = a dead project in crypto culture.' },
          { type: 'highlight', title: 'The Content Pyramid', body: 'Educational content (how your protocol works, what problem it solves) → builds credibility. Market commentary (reacting to news, sharing alpha) → builds relevance. Community engagement (replies, threads, spaces) → builds relationships. Announcements (launches, partnerships) → builds excitement. Ratio should be roughly 60/20/15/5.' },
          { type: 'text', title: 'Token Incentives as Marketing', body: 'Airdrops, retroactive rewards, and governance token distributions are marketing tools as much as protocol mechanics. Uniswap\'s 400 UNI airdrop ($3,000+ per user) to early users created the most talked-about moment in DeFi history. The marketing value of a well-designed airdrop exceeds its cost — it generates coverage, community, and loyalty simultaneously.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Web3 marketing is community-first, not advertising-first. Twitter is the operating environment. Educational content builds credibility. Token incentives (airdrops) are marketing events as much as protocol mechanics.' },
        ]},
        { id: 'mkt_beg_l2', title: 'Building a Twitter Presence', slides: [
          { type: 'intro', title: 'The Platform That Matters Most', body: 'Crypto Twitter is a unique culture: a mix of technical experts, degens, VCs, founders, and anons. The norms, language, and content formats that work there are completely different from mainstream social media. Learning them is not optional.' },
          { type: 'text', title: 'Profile Optimization', body: 'Name: clear, recognizable (crypto persona or real name). Profile picture: high quality — ENS avatar, PFP NFT, or real photo. Bio: what you do + what you talk about + key credentials. Pinned tweet: your best content, most important announcement, or thread that explains your work. Cover image: professional or thematic. These 60 seconds determine if a new visitor follows or bounces.' },
          { type: 'text', title: 'Thread Culture', body: 'Twitter threads are the primary long-form content format in crypto. High-performing thread formulas: "I analyzed X for Y hours. Here\'s what I found: 🧵" Controversy hooks: "The truth about [popular belief] that nobody talks about:" Number hooks: "10 DeFi mistakes that cost me $50k (and how to avoid them)" Threads drive follows, shares, and retweets more than any other content format in crypto.' },
          { type: 'highlight', title: 'What Crypto Twitter Rewards', body: 'Alpha sharing: useful information others don\'t have. Being right about macro calls. Explaining complex concepts simply. Transparency about losses and mistakes. Building in public. Disagreeing with consensus thoughtfully. What it punishes: obvious FUD, paid shilling without disclosure, repetitive promotional content, accounts that only post about their own project.' },
          { type: 'text', title: 'Growth Tactics That Work', body: 'Reply to big accounts with genuinely insightful takes. Write threads on trending topics from your area of expertise. Quote tweet with your perspective. Create original research and data (gets pinned and shared). Engage with your followers\' content consistently. Host Twitter Spaces. Consistency over volume — 1 high-quality tweet beats 10 mediocre ones every time.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Crypto Twitter culture rewards alpha, transparency, and insight. Threads are the primary content format. Profile optimization is conversion — first impressions matter. Growth comes from genuine engagement, not broadcasting.' },
        ]},
        { id: 'mkt_beg_l3', title: 'Discord Community Building', slides: [
          { type: 'intro', title: 'Your Home Base', body: 'Discord is where your community lives — where holders discuss, where developers get support, where governance happens, and where the culture of your project is formed. A thriving Discord is a competitive moat. A dead Discord is the first signal of a failing project.' },
          { type: 'text', title: 'Discord Architecture', body: 'Essential channels: #announcements (major updates), #general (main chat), #dev-updates (technical), #trading (price chat, price-isolated from main culture), #support (ticketing or direct help), #governance (proposals and voting), #showcase (members sharing their work). Separate serious discussion from price speculation — mixing them pollutes both.' },
          { type: 'text', title: 'Moderation at Scale', body: 'As your community grows: hire community managers (CMs). Establish clear rules with consequences. Use MEE6 or Carl-bot for auto-moderation. Define community culture early — the first 500 members set the norms. A Discord where price spam dominates is a Discord where nothing else can flourish.' },
          { type: 'highlight', title: 'Engagement Programs', body: 'Community-run programs that sustain engagement: weekly AMAs with the team. Contributor programs (pay community members to create content, translate, run campaigns). Governance participation incentives. Bug bounties. Art contests. Ambassador programs for geographic expansion. Engagement dies without intentional programming.' },
          { type: 'text', title: 'Converting Discord to Advocates', body: 'Your most engaged Discord members are your best marketing channel. Identify "power users" — the ones helping others, creating content, defending the project on Twitter. Give them roles, recognition, and early access. The Bored Ape Yacht Club Discord created a community so tight that members formed real-world businesses together. This is the ultimate Discord success — organic advocacy at scale.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Discord architecture, moderation, and engagement programming create thriving communities. Separate price discussion from core community culture. Identify and empower power users. Community advocates are your best marketing channel.' },
        ]},
        { id: 'mkt_beg_l4', title: 'Content Marketing in Web3', slides: [
          { type: 'intro', title: 'Education as Distribution', body: 'The best Web3 content marketers don\'t market their product directly — they educate their audience about the problem their product solves. Uniswap Labs doesn\'t need to advertise; the entire DeFi industry writes about AMMs for them. Educational content creates inbound authority.' },
          { type: 'text', title: 'The Blog and Medium Stack', body: 'Mirror.xyz: the Web3-native blogging platform (posts are NFTs, tip with crypto). Medium: still the dominant platform for crypto longform. Substack: best for newsletters. GitHub: developer documentation. The most trusted projects publish detailed technical posts — not just announcements. Compound publishes protocol math. Uniswap publishes research. Transparency = credibility.' },
          { type: 'text', title: 'YouTube in Crypto', body: 'Crypto YouTube is massive: Coin Bureau (3M+ subs), Whiteboard Crypto, Benjamin Cowen. These creators reach retail audiences that Twitter doesn\'t. Partner with relevant YouTubers for sponsored explanations (not ads). Sponsor content that genuinely explains your protocol — not 60-second promos. Educational videos get watched for months; ads get skipped.' },
          { type: 'highlight', title: 'The Research Report', body: 'Publish original research: on-chain data analysis, protocol comparisons, market reports. Messari (analytics firm) built its $300M reputation on research reports. Delphi Digital, Nansen, and Chainalysis all monetize data and research. Even a project blog with original data analysis attracts links, coverage, and Twitter shares from researchers who cite your work.' },
          { type: 'text', title: 'Technical Documentation as Marketing', body: 'For developer-focused projects: your documentation IS your marketing. Bad docs = no developers. Excellent docs (like Chainlink\'s, Alchemy\'s) attract developers who build on your protocol, each of whom brings their own users. Gitbook is the standard Web3 documentation platform. Invest in documentation as seriously as you invest in code.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Educational content > direct promotion. Mirror/Medium for longform. YouTube partnerships for retail reach. Original research establishes credibility and earns links. For developer protocols, documentation quality determines adoption.' },
        ]},
        { id: 'mkt_beg_l5', title: 'PR and Media Coverage', slides: [
          { type: 'intro', title: 'The Crypto Media Landscape', body: 'Crypto media is a unique ecosystem of publications, newsletters, and podcasters that reach different audiences with different credibility levels. Understanding who covers what — and how to get coverage — is a core growth lever.' },
          { type: 'text', title: 'The Publication Hierarchy', body: 'CoinDesk and The Block: mainstream crypto news (broad audience, high credibility). Decrypt: accessible crypto journalism. Bankless: DeFi-native, deep dives (trust among DeFi users). The Defiant: DeFi-focused journalism. Unchained Podcast (Laura Shin): longest-form, high-quality interviews. Milestone announcements → CoinDesk. Technical deep dives → Bankless. Community stories → smaller publications and podcasts.' },
          { type: 'text', title: 'Getting Press Coverage', body: 'Real milestones get coverage: first $1B TVL, major exploit, significant partnership, protocol launch. Journalists need: clear "what happened," quantified impact, available quote from founder, supporting data. Send press releases 24 hours before embargo lifts. Exclusives drive better coverage — offer CoinDesk or The Block exclusive embargo access for major announcements. Never pay for editorial coverage.' },
          { type: 'highlight', title: 'The Podcast Circuit', body: 'Podcast appearances build credibility more than articles. Bankless, Unchained, Delphi Media, Empire, Blockworks Macro — these audiences are highly sophisticated. Appearance on Bankless is worth more than most paid marketing. Send a cold pitch: "I\'m the founder of X, we just did Y (major milestone), I have a novel take on Z (interesting topic). Would love to come on." Metrics and novel insights get responses.' },
          { type: 'text', title: 'Managing Bad Press', body: 'Every significant project faces negative coverage: exploit reports, regulatory coverage, competitor accusations. Protocol: respond quickly (silence is guilt in crypto). Be factual, not defensive. Acknowledge what\'s true. Correct what\'s false with evidence. Don\'t attack journalists. Bad press handled well (immediate disclosure, clear remediation plan) can paradoxically build trust. Bad press ignored destroys it.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Crypto media hierarchy: CoinDesk for news, Bankless for DeFi depth, podcasts for credibility building. Exclusives get better coverage. Podcast appearances are worth more than articles. Negative press handled with transparency becomes trust-building.' },
        ]},
      ],
      quiz: [
        { id: 'mkt_beg_q1', question: 'How does Web3 marketing differ fundamentally from traditional marketing?', options: ['Web3 uses more advertising', 'Web3 builds communities of stakeholders (who own tokens and have governance rights) rather than acquiring customers through paid channels — community becomes the distribution network', 'Web3 marketing is purely digital, while traditional is physical', 'Web3 relies exclusively on influencer marketing'], correct: 1, explanation: 'Traditional marketing: pay to reach customers. Web3: build a community where users are token holders, governance participants, and advocates simultaneously. This creates more loyal but more demanding audiences — they expect genuine value, not just marketing.' },
        { id: 'mkt_beg_q2', question: 'What content format performs best on Crypto Twitter?', options: ['Short promotional tweets about your project', 'Threads that share alpha, original research, or explain complex topics simply — especially with compelling hooks like "I analyzed X for Y hours"', 'Daily price updates and market commentary', 'Retweets of major crypto accounts'], correct: 1, explanation: 'Threads are the premier crypto Twitter content format. They enable in-depth exploration of topics, can be shared/bookmarked as a unit, and get algorithmic amplification. The hook (first tweet) determines if people click "show more" — compelling hooks are as important as the content itself.' },
        { id: 'mkt_beg_q3', question: 'Why should price discussion be separated from general community channels in Discord?', options: ['Price discussion violates Discord\'s terms of service', 'Mixing price speculation with core community culture pollutes both — price-focused channels attract traders who leave in bear markets, while separating them lets genuine builders and users thrive regardless of market conditions', 'To prevent legal liability', 'Price discussions require special moderation tools'], correct: 1, explanation: 'Price-dominated Discords attract mercenary members who leave when prices fall. Separating price discussion lets core builders and genuine users have meaningful conversations. Projects with vibrant non-price community discussions survive bear markets; price-only Discords empty out.' },
        { id: 'mkt_beg_q4', question: 'What makes Bankless podcast appearances more valuable than most paid marketing?', options: ['Bankless has the highest podcast viewership in crypto', 'The Bankless audience is highly sophisticated DeFi users — appearances build deep credibility with exactly the users protocols need most, unlike paid ads that reach broad audiences with low intent', 'Bankless is the cheapest marketing channel', 'Bankless offers guaranteed protocol coverage'], correct: 1, explanation: 'Bankless listeners are serious DeFi participants, developers, and researchers — not casual observers. Appearing on Bankless means engaging an audience of potential heavy users and opinion leaders. This high-intent, high-sophistication audience is more valuable than broad reach.' },
        { id: 'mkt_beg_q5', question: 'What is the recommended approach when your protocol gets negative press coverage?', options: ['Ignore it; engaging amplifies the coverage', 'Sue the journalist for defamation', 'Respond quickly with facts — acknowledge what\'s true, correct what\'s false with evidence, don\'t attack journalists. Transparency in a crisis builds more trust than silence or defensiveness', 'Only respond if the coverage is from a major publication'], correct: 2, explanation: 'In crypto, silence = guilt. Communities expect real-time transparency. Responding quickly and factually to negative coverage — even exploits — demonstrates accountability. Projects that disclosed hacks immediately and communicated remediation plans often maintained community trust. Those that went silent lost it permanently.' },
      ],
    },
    {
      id: 'marketing_int',
      level: 'intermediate',
      title: 'Growth Strategies',
      emoji: '🚀',
      description: 'Token launches, airdrop campaigns, KOL partnerships, and viral growth mechanics.',
      color: '#EF4444',
      lessons: [
        { id: 'mkt_int_l1', title: 'Token Launch Marketing', slides: [
          { type: 'intro', title: 'The Most Important Event', body: 'A token launch is a crypto project\'s IPO, product launch, and community founding event simultaneously. Done right, it creates a permanent community of stakeholders. Done wrong, it creates a permanent community of bagholders who resent the team.' },
          { type: 'text', title: 'Launch Types', body: 'Fair launch: no VC allocation, everyone has equal access. Maximum credibility, harder to fund development. ICO (Initial Coin Offering): raise capital before launch. 2017-2018 era, heavily regulated now. IDO (Initial DEX Offering): public sale on a DEX launchpad (DAO Maker, TrustSwap, Polkastarter). IEO (Initial Exchange Offering): sold through a centralized exchange. Most 2024 tokens launch with VC + seed investors + public sale + team allocation.' },
          { type: 'text', title: 'Tokenomics Narrative', body: 'The tokenomics narrative is as important as the tokenomics math. Tell the story: "X% goes to community (governed by holders). Y% to team (4-year vesting with 1-year cliff, proving alignment). Z% to ecosystem development (grants for builders). No private investors dumping — 18 month lock for all insiders." Vesting schedules on a public unlock calendar (token.unlocks.app) build trust.' },
          { type: 'highlight', title: 'The Launch Checklist', body: 'Pre-launch: smart contract audit published. Tokenomics document live. Community has 10,000+ engaged members. Tier 1 exchange listing confirmed. Day 1 liquidity plan. Coinmarketcap + CoinGecko listing prepared. Press embargo coordinated with 3-5 publications. Twitter/Discord announcement sequence planned. The launch is a coordinated campaign, not a single event.' },
          { type: 'text', title: 'Post-Launch Sustaining', body: 'The week after launch, most tokens dump 30-70% as short-term traders exit. This is normal. Your job: communicate. The team is still building. Here\'s this week\'s development update. Here\'s our next milestone. Here\'s who just integrated us. Consistent post-launch communication that focuses on real progress (not price) stabilizes the holder base and attracts long-term investors.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Token launches require coordinated multi-channel campaigns, not single announcements. Tokenomics narrative matters as much as the math. Post-launch communication — focused on progress, not price — converts speculators into long-term holders.' },
        ]},
        { id: 'mkt_int_l2', title: 'Airdrop Design and Execution', slides: [
          { type: 'intro', title: 'Airdrops as Marketing Events', body: 'Well-designed airdrops are the most powerful marketing tool in crypto. They create advocates overnight, generate press coverage, and reward the users who built your early adoption. Poorly designed airdrops attract farmers who dump immediately and create nothing.' },
          { type: 'text', title: 'Retroactive vs Prospective', body: 'Retroactive (Uniswap, ENS model): snapshot historical users and reward them for past behavior. Honest, rewards genuine early adopters. Prospective (Blur, dYdX model): announce future airdrop criteria, attract activity to earn it. Risk: farming activity that doesn\'t represent real product-market fit. Best: combine — reward past users generously, announce future criteria to sustain activity.' },
          { type: 'text', title: 'Airdrop Criteria Design', body: 'Bad criteria: "hold 1 token for 30 days" (trivial to farm). Good criteria: use the protocol meaningfully — minimum transaction count + minimum volume + time diversity (not all in one day) + multiple protocol features used. The goal: your criteria should be hard to farm unless you\'re actually using the product. Study how Arbitrum, Optimism, and Starknet approached this.' },
          { type: 'highlight', title: 'The Sybil Problem', body: 'Sybil attacks: create 1,000 wallets, do minimal interactions across all, claim 1,000 × airdrop amount. Mitigation: Gitcoin Passport (web of trust identity verification). On-chain activity patterns that distinguish real users from farming (gas spent on non-protocol transactions, cross-protocol usage, timing patterns). Exclude addresses with identical transaction fingerprints.' },
          { type: 'text', title: 'Communicating the Airdrop', body: 'Announcement day is everything. Clear criteria published. Interactive eligibility checker (users can self-check). Twitter thread explaining the reasoning behind criteria. Discord AMA to address questions. If there\'s controversy (there always is), acknowledge edge cases fairly and quickly. The Optimism retroactive airdrop post-mortem is the best public example of how to handle a complex airdrop communications campaign.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Airdrops reward genuine users, not farmers. Meaningful usage criteria + Sybil detection filter mercenary participants. Retroactive rewards genuine adopters; prospective criteria sustain growth. Airdrop announcement communications are as important as the criteria themselves.' },
        ]},
        { id: 'mkt_int_l3', title: 'KOL and Influencer Marketing', slides: [
          { type: 'intro', title: 'Key Opinion Leaders in Crypto', body: 'KOL (Key Opinion Leader) marketing is how crypto projects reach retail audiences at scale. But crypto KOL marketing has a uniquely skeptical audience — and a history of paid shilling that has eroded trust. Doing it right is very different from doing it cheaply.' },
          { type: 'text', title: 'The KOL Landscape', body: 'Tier 1 KOLs: Coinbureau, Altcoin Daily, DataDash — 500k-3M YouTube subscribers, broad retail reach. Tier 2: Crypto Twitter personalities with 100k-500k followers — niche trust. Tier 3: Micro-influencers 10k-100k — specific communities. Tier 1 reach costs $50k-$500k per integration. Tier 2: $5k-$50k. Tier 3: $500-$5k. ROI varies wildly based on authenticity.' },
          { type: 'text', title: 'Authentic vs Shill', body: 'The most effective KOL partnerships: the KOL actually uses the product and reports genuine findings. The least effective and most dangerous: KOL receives tokens, makes price predictions, pumps without disclosure. SEC has charged multiple influencers for undisclosed token promotions. Always require FTC-compliant disclosure (#ad or #paid). Audiences detect inauthenticity immediately — and it destroys the KOL\'s effectiveness for you.' },
          { type: 'highlight', title: 'The Ambassador Program', body: 'Instead of one-off paid posts, build an ambassador program: 50-100 authentic community members across geographies and niches. Give them early access, governance tokens, and support resources. They create content because they genuinely believe in the project. Their audiences trust them because of their track record — not because they were paid to say something. This scales better than any paid KOL campaign.' },
          { type: 'text', title: 'Measuring KOL ROI', body: 'Vanity metrics: views, likes, follower count. Real metrics: UTM-tracked link clicks to your DApp, wallet connections from campaign traffic, new wallet activations from referred addresses (possible via Dune Analytics query), trading volume from KOL discount codes. Crypto KOL measurement is hard — on-chain attribution provides better signal than URL clicks.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Authentic KOL marketing beats paid shilling. Ambassador programs (100 authentic advocates) outperform one-off paid posts. Require FTC disclosure on all paid content. Measure on-chain results — wallet activations and volume — not vanity metrics.' },
        ]},
        { id: 'mkt_int_l4', title: 'Growth Hacking Web3', slides: [
          { type: 'intro', title: 'Crypto-Native Growth Mechanics', body: 'Web3 growth hacking uses token incentives, on-chain referrals, and community mechanics that don\'t exist in traditional growth. Understanding these mechanics lets you design virality into your protocol from day one.' },
          { type: 'text', title: 'Referral Programs with Tokens', body: 'On-chain referral programs: bring a user to the protocol, earn a % of their fees permanently. Friend.tech paid referrers 5% of referred users\' key trading fees indefinitely. This created powerful word-of-mouth: 10 referrals earning 5% each = meaningful passive income. dYdX v3 gave DYDX tokens for referring traders. Referral mechanics with real token value are self-propagating.' },
          { type: 'text', title: 'Points Programs', body: 'Pre-airdrop points programs: use protocol → earn points → points convert to tokens at TGE. Blur\'s BLUR farming, EigenLayer\'s pre-launch points, Hyperliquid\'s points — each created massive engagement in anticipation of airdrop. Risk: mercenary activity that doesn\'t represent real users. Mitigation: design points criteria around genuine protocol usage rather than trivial actions.' },
          { type: 'highlight', title: 'Virality by Design: Friend.tech', body: 'Friend.tech (2023) created organic virality through its model: buy someone\'s "key" to chat with them in a private room. Key prices rise with demand (bonding curve). Early buyers of influential people\'s keys profit if more people buy later. The mechanism created instant speculation and FOMO — Twitter was flooded with people announcing their key price. $100M in volume in 2 weeks. Viral mechanics built into the protocol itself.' },
          { type: 'text', title: 'Community-Driven Growth', body: 'The most sustainable growth is community-driven: make it easy for users to share achievements on social media. "I just earned 500 XP on X protocol" Twitter integration. On-chain reputation badges that users display publicly. Leaderboards. Competition. These mechanics from gaming (status, competition, achievement) translate powerfully to crypto communities.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Token referrals, points programs, and viral protocol mechanics create crypto-native growth that doesn\'t exist in Web2. Design virality into the protocol mechanics themselves (Friend.tech model). Sustain with community-driven achievement sharing.' },
        ]},
        { id: 'mkt_int_l5', title: 'Community-Led Marketing', slides: [
          { type: 'intro', title: 'When Your Users Market for You', body: 'The most cost-effective and credible marketing happens when your community becomes your marketing team. This requires a deliberate program — it doesn\'t happen spontaneously — but when it works, it creates compounding returns that no paid campaign can match.' },
          { type: 'text', title: 'Grants for Community Content', body: 'Uniswap Grants, Aave Grants DAO, and Compound Grants all fund community members to create tutorials, translations, research, and tools. The community creates better content than your in-house team because they know their local context. Grant recipients are also your most vocal advocates — they have financial skin in the game to see the project succeed.' },
          { type: 'text', title: 'The DAO Marketing Committee', body: 'For decentralized protocols: a marketing DAO committee funded by the treasury. Community votes on marketing budget. Committee executes: hires freelance designers, coordinates campaigns, manages KOL relationships, reports results publicly. This model democratizes marketing decisions and creates accountability — community members can vote down bad campaigns and approve proven strategies.' },
          { type: 'highlight', title: 'Translation and Localization', body: 'Korean, Chinese, Japanese, Turkish, and Spanish crypto communities are massive and underserved by English-only content. Pay community members to translate documentation, educational content, and Discord into their languages. Create language-specific Discord channels with native moderators. Non-English communities often have higher engagement and less saturation from competitors.' },
          { type: 'text', title: 'Measuring Community Health', body: 'Daily active Discord users. Discord message count (non-bot). Twitter mentions per week. Organic (non-paid) content pieces created about your project. Waitlist or application conversion rates. GitHub contributors. Protocol governance participation rate. These metrics tell you whether your community is genuinely engaged or a hollow shell of bots and mercenary participants.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Grants fund community content creation. DAO marketing committees democratize campaigns. Translation programs unlock non-English communities. Measure community health through engagement metrics, not follower counts. Community-led marketing compounds; paid marketing doesn\'t.' },
        ]},
      ],
      quiz: [
        { id: 'mkt_int_q1', question: 'What is the primary risk of prospective airdrop campaigns (announcing future criteria)?', options: ['They are illegal under SEC regulations', 'They attract farming activity — users performing minimum required actions across many wallets without genuine product engagement', 'They are more expensive than retroactive campaigns', 'They require smart contract upgrades'], correct: 1, explanation: 'Prospective airdrops tell users exactly what activity earns tokens. Sophisticated farmers create dozens of wallets and perform exactly those actions — generating inflated user metrics without real product-market fit. The challenge is designing criteria hard enough to filter farmers while accessible to genuine users.' },
        { id: 'mkt_int_q2', question: 'What makes Ambassador programs more sustainable than one-off KOL campaigns?', options: ['Ambassadors cost nothing compared to KOLs', 'Ambassadors are authentic community believers who create content because they genuinely use the product — their audiences trust them because of their track record, not because they were paid', 'Ambassadors reach larger audiences', 'Ambassadors don\'t require FTC disclosure'], correct: 1, explanation: 'One-off paid KOL posts: expensive, audience-detectable as paid, low conversion. 100 authentic ambassadors: their audiences trust them because of their history, they create sustained content, they know the product deeply, and their coverage compounds over time. Authenticity is the scarcest resource in crypto marketing.' },
        { id: 'mkt_int_q3', question: 'How did Friend.tech create viral growth through its protocol mechanics?', options: ['It paid influencers to promote the platform', 'The "key" bonding curve made key prices rise with demand — early holders profited if more users joined, creating natural FOMO and word-of-mouth as users publicly announced their key prices', 'It launched with a massive airdrop', 'It partnered with major crypto exchanges'], correct: 1, explanation: 'Friend.tech\'s key bonding curve made early buyers of influential users\' keys profit as more people joined. This created: (1) financial incentive to recruit others, (2) public Twitter announcements of key prices, (3) FOMO from watching prices rise. Viral mechanics built into the protocol generated $100M volume in 2 weeks organically.' },
        { id: 'mkt_int_q4', question: 'What on-chain metric best measures genuine KOL campaign effectiveness?', options: ['Total video views and likes', 'New wallet activations and protocol volume from referred addresses — attributed via Dune Analytics or on-chain referral codes', 'KOL follower count', 'Discord member growth during campaign period'], correct: 1, explanation: 'Views and follows are easy to fake and don\'t represent users. On-chain data reveals real behavior: how many new wallets appeared from the KOL\'s referral link? How much volume did they generate? Did they use the protocol more than once? This crypto-native attribution reveals the actual ROI of the campaign.' },
        { id: 'mkt_int_q5', question: 'Why should you measure Discord "daily active users" rather than total member count?', options: ['Total member count is not available in Discord\'s analytics', 'Total members are vanity metrics — discord servers routinely have 80%+ inactive members. Daily active users reveal the actual engaged community size, which is what determines marketing power and protocol health', 'Discord only shows active users in its analytics', 'Total member count inflates due to bot accounts'], correct: 1, explanation: 'A 100,000-member Discord with 200 daily active users is less valuable than a 5,000-member Discord with 800 daily active users. The active community members create culture, help new users, share feedback, and advocate publicly. Member count is easy to inflate through paid promotions; engagement cannot be faked.' },
      ],
    },
    {
      id: 'marketing_exp',
      level: 'expert',
      title: 'Protocol Growth at Scale',
      emoji: '🌐',
      description: 'Ecosystem development, institutional BD, narrative building, and global expansion.',
      color: '#EF4444',
      lessons: [
        { id: 'mkt_exp_l1', title: 'Narrative Engineering', slides: [
          { type: 'intro', title: 'Markets Move on Narratives', body: 'In crypto, price follows narrative — not fundamentals, not even adoption metrics. The protocol that controls its narrative controls its perception, its price, and its ability to attract talent and capital. Narrative engineering is the highest-leverage marketing skill in crypto.' },
          { type: 'text', title: 'The Narrative Hierarchy', body: 'Macro narratives (DeFi summer, NFT boom, Layer 2 thesis, RWA narrative) lift entire sectors. Sector narratives (LSDfi, restaking, modular blockchains) lift segments within sectors. Protocol narratives ("the most capital-efficient yield protocol," "the first truly decentralized stablecoin") position you within your sector. The macro and sector lift your protocol; your protocol narrative must capture your sector\'s momentum.' },
          { type: 'text', title: 'Creating vs Riding Narratives', body: 'Narrative riding: identify the emerging narrative early, position your project as central to it, create content connecting your work to the trend. Ethereum restaking was emerging when EigenLayer positioned itself as the restaking protocol — their narrative captured the entire trend. Narrative creation: harder, higher reward. Olympus DAO invented "Protocol-Owned Liquidity" as a narrative — attracted $1B+ before anyone else understood it.' },
          { type: 'highlight', title: 'The Whitepaper as Narrative', body: 'Satoshi\'s whitepaper is a masterpiece of narrative: "peer-to-peer electronic cash" clearly positioned Bitcoin vs. existing payment systems. Ethereum\'s "world computer" narrative expanded the market. Whitepaper quality signals team credibility, defines the problem you\'re solving, and frames how all future coverage will describe your protocol. It\'s marketing literature as much as technical documentation.' },
          { type: 'text', title: 'Narrative Warfare', body: 'When competing protocols fight for the same narrative, the battle is on Twitter, podcasts, and at conferences. Ethereum vs. Solana: decentralization/security vs. speed/cost. Bitcoin maximalists vs. "shitcoin" advocates. These narrative wars define perception for years. Engaging authentically, with data and logic, is more effective long-term than dismissing competitors — even if the short-term Twitter engagement is lower.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Narrative precedes adoption and price. Ride macro narratives; create sector narratives when possible. The whitepaper frames all future coverage. Narrative wars define perception — engage with data and authenticity, not dismissal.' },
        ]},
        { id: 'mkt_exp_l2', title: 'Business Development', slides: [
          { type: 'intro', title: 'Partnerships That Create Network Effects', body: 'In DeFi, protocol integrations create genuine network effects — Chainlink\'s price feeds in 1,000+ protocols mean Chainlink is essential infrastructure. BD at the protocol level is about creating integrations that lock in dependency and expand your total addressable market.' },
          { type: 'text', title: 'Types of Partnerships', body: 'Technical integrations: another protocol builds on yours (highest value). Liquidity partnerships: co-incentivize a trading pair or lending market. Co-marketing: joint announcements, content, community events. Ecosystem grants: you fund projects building on your protocol. Exchange listings: CEX listings for your token. Each has different strategic value — technical integrations create the most defensible moats.' },
          { type: 'text', title: 'The BD Pitch', body: 'When approaching protocols for integration: lead with user benefit, not your benefit. "Integrating Chainlink would give your users 99.9% uptime oracle coverage with $75B+ in secured value — vs building your own oracle with unknown reliability." Show the other protocol exactly what their users gain. The best BD doesn\'t ask for a favor — it presents an obvious win for both sides.' },
          { type: 'highlight', title: 'Conference Strategy', body: 'ETHDenver, Devcon, Permissionless, Token2049, Korea Blockchain Week — these conferences are where protocol BD happens. Budget $50k-$200k per major conference: side events, sponsorships, developer workshops, hackathon prizes. The most productive conference activity: 1:1 meetings with potential integration partners. Come with a meeting list and leave with signed integration commitments.' },
          { type: 'text', title: 'Institutional BD', body: 'By 2024, TradFi institutions are the next growth layer. BlackRock BUIDL, Franklin Templeton FOBXX, and JPMorgan\'s blockchain experiments. Institutional BD requires: compliance-ready documentation, legal structure for their counterpart risk requirements, long sales cycles (6-18 months), executive relationships, and the ability to accommodate institutional-specific requirements (KYC/AML, custody). It\'s TradFi BD with crypto technical requirements.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Protocol integrations create the strongest BD moats. Lead BD pitches with partner user benefit, not your own. Conferences are BD execution environments — come with a meeting list. Institutional BD has longer cycles but transformative scale.' },
        ]},
        { id: 'mkt_exp_l3', title: 'Global Community Expansion', slides: [
          { type: 'intro', title: 'Crypto is a Global Market', body: 'South Korea, Japan, Turkey, Nigeria, Vietnam, and Brazil are among the world\'s most active crypto markets — often with more per-capita adoption than the US. English-only marketing misses the majority of the global crypto opportunity.' },
          { type: 'text', title: 'Asian Markets', body: 'Korea: Bithumb and Upbit are massive. Korean retail has driven "Kimchi Premium" (BTC trading 10%+ above global price). Strong gaming community = strong NFT/gaming market. Japan: FSA-regulated, institutional. LINE and Yahoo Japan both have crypto products. Vietnam, Philippines: mobile-first, DeFi-native (Axie Infinity peak was Vietnam-driven). Build Korea/Japan strategy differently: local teams, local exchange listings, local media.' },
          { type: 'text', title: 'Emerging Markets', body: 'Nigeria: 35% of adults own crypto (highest globally). Driven by naira instability + remittance needs. Turkish adoption driven by 75%+ inflation. Latin America: El Salvador Bitcoin legal tender; Argentina, Venezuela hyperinflation driving real crypto utility. These markets aren\'t speculating — they\'re using crypto for financial survival. Marketing to them requires understanding local financial pain points, not just crypto culture.' },
          { type: 'highlight', title: 'Localization Beyond Translation', body: 'Real localization means: payment method support (M-Pesa in Africa, PIX in Brazil). Fiat on-ramp partnerships with local banks or exchanges. Content in local language created by native speakers (not Google Translate). Community managers who understand local context. Regulatory compliance for each jurisdiction. A translated website is not localization. Local teams and infrastructure are.' },
          { type: 'text', title: 'Region-Specific Marketing Channels', body: 'China: WeChat, Weibo (Twitter/Discord not available). Korea: KakaoTalk, Naver blog, Telegram. Japan: Twitter is uniquely popular, LINE apps. Turkey: Telegram is dominant. Nigeria/Africa: Twitter, Telegram, WhatsApp groups. Understanding which platforms dominate each region determines where to invest — and who to hire locally to manage them.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Global crypto adoption is heaviest in Asia and emerging markets. Each region has unique drivers (speculation vs utility), platforms (WeChat vs Telegram), and regulatory contexts. True localization requires local teams, not just translations.' },
        ]},
        { id: 'mkt_exp_l4', title: 'Data-Driven Marketing', slides: [
          { type: 'intro', title: 'On-Chain Analytics as Marketing Intelligence', body: 'Crypto marketing has a unique advantage over traditional marketing: every protocol interaction is public on-chain. Who\'s using you, what they\'re doing, where they came from, and how much they\'re spending — all publicly visible. This is the richest product analytics data in the history of business.' },
          { type: 'text', title: 'Dune Analytics for Marketing', body: 'Custom Dune dashboards reveal: daily active wallets, cumulative unique users, retention (users who return week 2+), transaction size distribution (whale vs retail mix), top referring protocols/integrations, geographic distribution (by on-chain payment patterns). Public dashboards attract press coverage and investor interest — Uniswap\'s Dune dashboard is cited in major media constantly.' },
          { type: 'text', title: 'Retention Metrics', body: 'Acquisition is overrated; retention is everything. Measure: D1 retention (% of Day 1 users active on Day 2), D7, D30. Crypto retention benchmarks: DeFi protocols typically see 10-20% D30 retention; games see 5-15%. Improving D30 retention by 5 percentage points compresses user acquisition cost more than any marketing campaign.' },
          { type: 'highlight', title: 'Cohort Analysis On-Chain', body: 'On-chain cohort analysis: identify wallets that first transacted in a specific month. Track their behavior over time. Do January 2024 users spend more or less than January 2023 users? Are post-airdrop users more or less engaged than pre-airdrop organic users? These cohort insights reveal whether your marketing is attracting the right users — or mercenary capital.' },
          { type: 'text', title: 'A/B Testing in Crypto', body: 'Website A/B testing (Optimizely, VWO): test CTAs, landing page copy, UI flows. Email A/B (Beehiiv, Mailchimp): subject line, send time, content format. Discord A/B: test different announcement formats. On-chain A/B: deploy two liquidity programs with different incentive structures and measure adoption. Data-driven iteration compounds over time.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'On-chain data is the richest marketing intelligence ever created. Dune dashboards surface publicly and attract press. Retention (D30) matters more than acquisition. Cohort analysis separates genuine users from mercenary participants. A/B testing compounds improvement over time.' },
        ]},
        { id: 'mkt_exp_l5', title: 'Building a Marketing Team', slides: [
          { type: 'intro', title: 'Scaling Marketing Infrastructure', body: 'Early-stage protocols have a founder-led marketing function. As they scale, building a specialized team — content, community, growth, BD — determines whether marketing compounds or stagnates. Building this team in crypto is uniquely challenging.' },
          { type: 'text', title: 'Core Roles', body: 'Head of Marketing/Growth: strategy, budgeting, team leadership. Community Manager: Discord/Telegram management, 24/7 responsiveness required. Content Lead: Twitter, blog, thread creation. Growth Engineer: on-chain analytics, referral programs, growth experiments. Business Development: exchange listings, protocol partnerships, institutional outreach. Each role requires crypto-native experience — Web2 marketing skills without crypto context are insufficient.' },
          { type: 'text', title: 'Where to Find Crypto Marketers', body: 'Your own Discord: power users who already love your project. Protocol alumni: former Uniswap, Aave, Coinbase employees. Crypto-native agencies (Coinstack, FN Media Group). Freelancer DAOs (Raid Guild, Mirror). Conference networking. The best crypto marketers are often anonymous Twitter accounts with 50k followers and a proven track record of building communities — not former FMCG brand managers.' },
          { type: 'highlight', title: 'Token Compensation', body: 'Marketing teams in crypto expect token allocations, not just salary. 0.1-0.5% token allocation over 2-4 year vest for senior hires. This aligns incentives — your marketing team\'s compensation is correlated with protocol success. Risk: if the token crashes, your team\'s effective compensation collapses. Combine base salary + token allocation for stability.' },
          { type: 'text', title: 'Marketing Budget Allocation', body: 'For a $5M annual marketing budget in 2024 (approximate): Community operations: 25% ($1.25M). Content creation + media: 20% ($1M). KOL/Ambassador programs: 20% ($1M). Events and conferences: 15% ($750k). Paid acquisition (targeted): 10% ($500k). Growth experiments: 5% ($250k). BD travel + entertainment: 5% ($250k). Allocations shift based on protocol stage — early stage is community-heavy, growth stage is acquisition-heavy.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Protocol marketing teams require crypto-native skills. Hire from your own community, protocol alumni, and crypto-native agencies. Token + salary compensation aligns long-term incentives. Budget allocation should reflect protocol stage — community-heavy early, acquisition-heavy at scale.' },
        ]},
      ],
      quiz: [
        { id: 'mkt_exp_q1', question: 'What is "narrative engineering" in crypto marketing?', options: ['Writing technical documentation', 'Deliberately crafting and controlling your project\'s story — what problem you solve, what category you own, and how you connect to macro trends — because markets move on narrative before fundamentals', 'SEO optimization for crypto websites', 'Managing press releases'], correct: 1, explanation: 'In crypto, narrative precedes adoption and price. The protocol that defines the narrative of its category (EigenLayer = restaking, Chainlink = oracles) attracts all the attention and capital in that category. Narrative engineering is deliberate positioning — not just describing your product, but defining the space.' },
        { id: 'mkt_exp_q2', question: 'What makes protocol integrations the highest-value BD activity?', options: ['They are the cheapest partnership type', 'Integrations create genuine dependency — other protocols build on yours, making your infrastructure essential and creating compounding network effects (more integrations = more valuable for each additional integrator)', 'They require the least legal work', 'Exchange listings generate more value'], correct: 1, explanation: 'When Chainlink is integrated into 1,000+ protocols, those protocols are dependent on Chainlink. Each new integration makes Chainlink more valuable as a proven standard. This is infrastructure lock-in through network effects. Token marketing creates temporary price spikes; protocol integrations create permanent moats.' },
        { id: 'mkt_exp_q3', question: 'Why does Nigeria have among the highest per-capita crypto adoption globally?', options: ['Nigeria has the best blockchain infrastructure in Africa', 'Naira instability, 35% of adults owning crypto driven by real financial utility — remittances, inflation hedging, and USD access — not speculation', 'Nigeria has the most crypto-friendly regulations', 'Nigerian universities offer blockchain degrees'], correct: 1, explanation: 'Nigeria\'s crypto adoption is utility-driven, not speculative. With naira devaluation, restricted access to dollars, and high remittance needs, crypto (especially USDT) solves real financial problems. This creates more loyal, durable users than speculation-driven adoption — they\'re using crypto because they need to.' },
        { id: 'mkt_exp_q4', question: 'What does D30 retention measure and why does it matter more than acquisition?', options: ['The number of users acquired in the last 30 days', 'The percentage of Day 1 users who are still active on Day 30 — improving retention by 5% compounds into higher LTV per user, reducing the cost of growth more than any acquisition campaign', 'Daily active users over a 30-day period', 'Monthly active users from paid campaigns'], correct: 1, explanation: 'If you acquire 1,000 users but only 5% remain after 30 days, you need to acquire 1,000 users again next month. If you improve D30 retention to 10%, each user cohort lasts twice as long — cutting acquisition cost in half. Retention improvement compounds; it\'s the single most impactful metric for sustainable growth.' },
        { id: 'mkt_exp_q5', question: 'Why is token compensation important for crypto marketing teams?', options: ['It replaces salary entirely, reducing protocol costs', 'It aligns team incentives with protocol success — team members who hold tokens benefit from growth and are motivated to build long-term, not just execute short-term campaigns', 'It is required by crypto employment regulations', 'It allows the protocol to pay less total compensation'], correct: 1, explanation: 'Token allocation (typically 0.1-0.5% over 2-4 year vest) means your marketing team\'s wealth is directly tied to the protocol\'s success. This alignment motivates long-term thinking, genuine advocacy, and better decisions. Combined with base salary for stability, it\'s the standard compensation model for senior crypto marketing hires.' },
      ],
    },
  ],
};

export default marketing;
